sp_header_footer.client_script:
api.controller = function($scope, $uibModal) {
  var c = this;

  $scope.openLogin = function() {
    $scope.modalInstance = $uibModal.open({
      templateUrl: 'modalLogin',
      scope: $scope
    });
  };
};

sp_header_footer.css:
.navbar {
  min-height: 50px;
  transition: 250ms opacity ease-in-out;
  border: 0;
  border-bottom: $sp-navbar-bottom-width solid $sp-navbar-divider-color;
  margin-bottom: 0;
  border-radius: 0;
}


.navbar-header {
  float: left;
}


.navbar-brand {
  height: 50px;
  padding: 0 15px;
  display: flex;
  align-items: center;
  max-height: 50px;
}


.navbar-brand img,
.navbar-brand span {
  max-height: $sp-logo-max-height;
  max-width: $sp-logo-max-width;
  overflow: hidden;
}


.nav > li > a {
  max-height: 50px;
  padding-top: 15px;
  padding-bottom: 15px;
}


nav .toggle-dropdown {
  height: 50px;
}


.navbar-right {
  float: right !important;
  display: flex !important;
  align-items: center;
}


.navbar-toggle {
  display: none !important;
}


.collapse {
  display: block !important;
}

sp_header_footer.script:
(function() {
  var menu = $sp.getValue('sp_rectangle_menu');
  data.menu = $sp.getWidgetFromInstance(menu);
  data.hasMenuItems = false;
  data.hasLogin = false;
  data.login_page = $sp.getValue('login_page');

  if (data.menu && data.menu.data) {
    data.menu.data.replace = true;
    if (data.menu.data.menu && data.menu.data.menu.items) {
      data.hasMenuItems = data.menu.data.menu.items.length > 0;
      for (var i in data.menu.data.menu.items) {
        var item = data.menu.data.menu.items[i];
        if (item.type == 'page' && item.sp_page == data.login_page)
          data.hasLogin = true;
      }
    }
  }
})();
